30	const UseStrictPlugin = require("./UseStrictPlugin");
31	
32	const WarnCaseSensitiveModulesPlugin = require("./WarnCaseSensitiveModulesPlugin");
33	
34	const WebpackIsIncludedPlugin = require("./WebpackIsIncludedPlugin");
35	
36	const AssetModulesPlugin = require("./asset/AssetModulesPlugin");
37	
38	const InferAsyncModulesPlugin = require("./async-modules/InferAsyncModulesPlugin");
39	
40	const ResolverCachePlugin = require("./cache/ResolverCachePlugin");
41	
42	const CommonJsPlugin = require("./dependencies/CommonJsPlugin");
43	
44	const HarmonyModulesPlugin = require("./dependencies/HarmonyModulesPlugin");
45	
46	const ImportMetaContextPlugin = require("./dependencies/ImportMetaContextPlugin");
47	const ImportMetaPlugin = require("./dependencies/ImportMetaPlugin");
48	
49	const ImportPlugin = require("./dependencies/ImportPlugin");
50	const LoaderPlugin = require("./dependencies/LoaderPlugin");
51	
52	const RequireContextPlugin = require("./dependencies/RequireContextPlugin");
53	const RequireEnsurePlugin = require("./dependencies/RequireEnsurePlugin");
54	const RequireIncludePlugin = require("./dependencies/RequireIncludePlugin");
55	
56	const SystemPlugin = require("./dependencies/SystemPlugin");
57	
58	const URLPlugin = require("./dependencies/URLPlugin");
59	
60	const WorkerPlugin = require("./dependencies/WorkerPlugin");
61	
62	const JavascriptModulesPlugin = require("./javascript/JavascriptModulesPlugin");
63	const JavascriptParser = require("./javascript/JavascriptParser");
64	
65	const JsonModulesPlugin = require("./json/JsonModulesPlugin");
66	
67	const ChunkPrefetchPreloadPlugin = require("./prefetch/ChunkPrefetchPreloadPlugin");
68	
69	const DataUriPlugin = require("./schemes/DataUriPlugin");
70	const FileUriPlugin = require("./schemes/FileUriPlugin");
71	
72	const DefaultStatsFactoryPlugin = require("./stats/DefaultStatsFactoryPlugin");
73	const DefaultStatsPresetPlugin = require("./stats/DefaultStatsPresetPlugin");
74	const DefaultStatsPrinterPlugin = require("./stats/DefaultStatsPrinterPlugin");
75	
76	const { cleverMerge } = require("./util/cleverMerge");
77	
78	/** @typedef {import("./webpack").WebpackPluginFunction} WebpackPluginFunction */
79	/** @typedef {import("./config/defaults").WebpackOptionsNormalizedWithDefaults} WebpackOptions */
80	/** @typedef {import("./config/normalization").WebpackOptionsInterception} WebpackOptionsInterception */
81	/** @typedef {import("./Compiler")} Compiler */
82	/** @typedef {import("./util/fs").InputFileSystem} InputFileSystem */
83	/** @typedef {import("./util/fs").IntermediateFileSystem} IntermediateFileSystem */
84	
85	const CLASS_NAME = "WebpackOptionsApply";
86	
87	class WebpackOptionsApply extends OptionsApply {
88		constructor() {
89			super();
90		}
91	
92		/**
93		 * Returns options object.
94		 * @param {WebpackOptions} options options object
95		 * @param {Compiler} compiler compiler object
96		 * @param {WebpackOptionsInterception=} interception intercepted options
97		 * @returns {WebpackOptions} options object
98		 */
99		process(options, compiler, interception) {
100			compiler.outputPath = options.output.path;
101			compiler.recordsInputPath = options.recordsInputPath || null;
102			compiler.recordsOutputPath = options.recordsOutputPath || null;
103			compiler.name = options.name;
104	
105			if (options.externals) {
106				// @ts-expect-error https://github.com/microsoft/TypeScript/issues/41697
107				const ExternalsPlugin = require("./ExternalsPlugin");
108	
109				new ExternalsPlugin(options.externalsType, options.externals).apply(
110					compiler
111				);
112			}
113	
114			if (options.externalsPresets.node) {
115				const NodeTargetPlugin = require("./node/NodeTargetPlugin");
116	
117				// Some older versions of Node.js don't support all built-in modules via import, only via `require`,
118				// but it seems like there shouldn't be a warning here since these versions are rarely used in real applications
119				new NodeTargetPlugin(
120					options.output.module ? "module-import" : "node-commonjs"
121				).apply(compiler);
122	
123				// Handle external CSS `@import` and `url()`
124				if (options.experiments.css) {
125					// @ts-expect-error https://github.com/microsoft/TypeScript/issues/41697
126					const ExternalsPlugin = require("./ExternalsPlugin");
127	
128					new ExternalsPlugin(
129						"module",
130						({ request, dependencyType, contextInfo }, callback) => {
131							if (
132								/\.css(?:\?|$)/.test(contextInfo.issuer) &&
133								/^(?:\/\/|https?:\/\/|#)/.test(request)
134							) {
135								if (dependencyType === "url") {
136									return callback(null, `asset ${request}`);
137								} else if (
138									(dependencyType === "css-import" ||
139										dependencyType === "css-import-local-module" ||
140										dependencyType === "css-import-global-module") &&
141									options.experiments.css
142								) {
143									return callback(null, `css-import ${request}`);
144								}
145							}
146	
147							callback();
148						}
149					).apply(compiler);
150				}
151			}
152			if (options.externalsPresets.webAsync || options.externalsPresets.web) {
153				const type = options.externalsPresets.webAsync ? "import" : "module";
154	
155				// @ts-expect-error https://github.com/microsoft/TypeScript/issues/41697
156				const ExternalsPlugin = require("./ExternalsPlugin");
157	
158				new ExternalsPlugin(type, ({ request, dependencyType }, callback) => {
159					if (/^(?:\/\/|https?:\/\/|#|std:|jsr:|npm:)/.test(request)) {
160						if (dependencyType === "url") {
161							return callback(null, `asset ${request}`);
162						} else if (
163							(dependencyType === "css-import" ||
164								dependencyType === "css-import-local-module" ||
165								dependencyType === "css-import-global-module") &&
166							options.experiments.css
167						) {
168							return callback(null, `css-import ${request}`);
169						} else if (/^(?:\/\/|https?:\/\/|std:|jsr:|npm:)/.test(request)) {
170							return callback(null, `${type} ${request}`);
171						}
172					}
173	
174					callback();
175				}).apply(compiler);
176			}
177			if (options.externalsPresets.electron) {
178				// Use ESM imports only when the targeted electron version supports them
179				const type =
180					options.output.module && options.output.environment.module
181						? "module-import"
182						: "node-commonjs";
183	
184				// Warn when ESM output is requested but the electron version lacks it (added in electron 28)
185				if (options.output.module && !options.output.environment.module) {
186					const WebpackError = require("./WebpackError");
187	
188					compiler.hooks.thisCompilation.tap(CLASS_NAME, (compilation) => {
189						compilation.warnings.push(
190							new WebpackError(
191								"'output.module' is enabled, but the targeted electron version does not support ECMAScript modules (added in electron 28). Electron built-in modules are externalized as 'node-commonjs'."
192							)
193						);
194					});
195				}
196	
197				if (options.externalsPresets.electronMain) {
198					// @ts-expect-error https://github.com/microsoft/TypeScript/issues/41697
199					const ElectronTargetPlugin = require("./electron/ElectronTargetPlugin");
200	
201					new ElectronTargetPlugin("main", type).apply(compiler);
202				}
203				if (options.externalsPresets.electronPreload) {
204					// @ts-expect-error https://github.com/microsoft/TypeScript/issues/41697
205					const ElectronTargetPlugin = require("./electron/ElectronTargetPlugin");
206	
207					new ElectronTargetPlugin("preload", type).apply(compiler);
208				}
209				if (options.externalsPresets.electronRenderer) {
210					// @ts-expect-error https://github.com/microsoft/TypeScript/issues/41697
211					const ElectronTargetPlugin = require("./electron/ElectronTargetPlugin");
212	
213					new ElectronTargetPlugin("renderer", type).apply(compiler);
214				}
215				if (
216					!options.externalsPresets.electronMain &&
217					!options.externalsPresets.electronPreload &&
218					!options.externalsPresets.electronRenderer
219				) {
220					// @ts-expect-error https://github.com/microsoft/TypeScript/issues/41697
221					const ElectronTargetPlugin = require("./electron/ElectronTargetPlugin");
222	
223					new ElectronTargetPlugin(undefined, type).apply(compiler);
224				}
225			}
226			if (options.externalsPresets.nwjs) {
227				// @ts-expect-error https://github.com/microsoft/TypeScript/issues/41697
228				const ExternalsPlugin = require("./ExternalsPlugin");
229	
230				new ExternalsPlugin("node-commonjs", "nw.gui").apply(compiler);
231			}
232	
233			new ChunkPrefetchPreloadPlugin().apply(compiler);
234	
235			if (typeof options.output.chunkFormat === "string") {
236				switch (options.output.chunkFormat) {
237					case "array-push": {
238						const ArrayPushCallbackChunkFormatPlugin = require("./javascript/ArrayPushCallbackChunkFormatPlugin");
239	
240						new ArrayPushCallbackChunkFormatPlugin().apply(compiler);
241						break;
242					}
243					case "commonjs": {
244						const CommonJsChunkFormatPlugin = require("./javascript/CommonJsChunkFormatPlugin");
245	
246						new CommonJsChunkFormatPlugin().apply(compiler);
247						break;
248					}
249					case "module": {
250						const ModuleChunkFormatPlugin = require("./esm/ModuleChunkFormatPlugin");
251	
252						new ModuleChunkFormatPlugin().apply(compiler);
253						break;
254					}
255					default:
256						throw new Error(
257							`Unsupported chunk format '${options.output.chunkFormat}'.`
258						);
259				}
260			}
261	
262			const enabledChunkLoadingTypes =
263				/** @type {NonNullable<WebpackOptions["output"]["enabledChunkLoadingTypes"]>} */
264				(options.output.enabledChunkLoadingTypes);
265	
266			if (enabledChunkLoadingTypes.length > 0) {
267				for (const type of enabledChunkLoadingTypes) {
268					const EnableChunkLoadingPlugin = require("./javascript/EnableChunkLoadingPlugin");
269	
270					new EnableChunkLoadingPlugin(type).apply(compiler);
271				}
272			}
273	
274			const enabledWasmLoadingTypes =
275				/** @type {NonNullable<WebpackOptions["output"]["enabledWasmLoadingTypes"]>} */
276				(options.output.enabledWasmLoadingTypes);
277	
278			if (enabledWasmLoadingTypes.length > 0) {
279				for (const type of enabledWasmLoadingTypes) {
280					const EnableWasmLoadingPlugin = require("./wasm/EnableWasmLoadingPlugin");
281	
282					new EnableWasmLoadingPlugin(type).apply(compiler);
283				}
284			}
285	
286			const enabledLibraryTypes =
287				/** @type {NonNullable<WebpackOptions["output"]["enabledLibraryTypes"]>} */
288				(options.output.enabledLibraryTypes);
289	
290			if (enabledLibraryTypes.length > 0) {
291				let once = true;
292				for (const type of enabledLibraryTypes) {
293					const EnableLibraryPlugin = require("./library/EnableLibraryPlugin");
294	
295					new EnableLibraryPlugin(type, {
296						// eslint-disable-next-line no-loop-func
297						additionalApply: () => {
298							if (!once) return;
299							once = false;
300							// We rely on `exportInfo` to generate the `export statement` in certain library bundles.
301							// Therefore, we ignore the disabling of `optimization.providedExport` and continue to apply `FlagDependencyExportsPlugin`.
302							if (
303								["module", "commonjs-static", "modern-module"].includes(type) &&
304								!options.optimization.providedExports
305							) {
306								new FlagDependencyExportsPlugin().apply(compiler);
307							}
308						}
309					}).apply(compiler);
310				}
311			}
312	
313			if (options.output.pathinfo) {
314				const ModuleInfoHeaderPlugin = require("./ModuleInfoHeaderPlugin");
315	
316				new ModuleInfoHeaderPlugin(options.output.pathinfo !== true).apply(
317					compiler
318				);
319			}
320	
321			if (options.output.clean) {
322				const CleanPlugin = require("./CleanPlugin");
323	
324				new CleanPlugin(
325					options.output.clean === true ? {} : options.output.clean
326				).apply(compiler);
327			}
328	
329			if (options.dotenv) {
330				const DotenvPlugin = require("./DotenvPlugin");
331	
332				new DotenvPlugin(
333					typeof options.dotenv === "boolean" ? {} : options.dotenv
334				).apply(compiler);
335			}
336	
337			let devtool =
338				interception === undefined ? options.devtool : interception.devtool;
339			devtool = Array.isArray(devtool)
340				? devtool
341				: typeof devtool === "string"
342					? [{ type: "all", use: devtool }]
343					: [];
344	
345			for (const item of devtool) {
346				const { type, use } = item;
347	
348				if (use) {
349					if (use.includes("source-map")) {
350						const hidden = use.includes("hidden");
351						const inline = use.includes("inline");
352						const evalWrapped = use.includes("eval");
353						const cheap = use.includes("cheap");
354						const moduleMaps = use.includes("module");
355						const noSources = use.includes("nosources");
356						const debugIds = use.includes("debugids");
357						const Plugin = evalWrapped
358							? require("./EvalSourceMapDevToolPlugin")
359							: require("./SourceMapDevToolPlugin");
360						const assetExt =
361							type === "javascript"
362								? /\.((c|m)?js)($|\?)/i
363								: type === "css"
364									? /\.(css)($|\?)/i
365									: /\.((c|m)?js|css)($|\?)/i;
366	
367						new Plugin({
368							test: evalWrapped ? undefined : assetExt,
369							filename: inline ? null : options.output.sourceMapFilename,
370							moduleFilenameTemplate:
371								options.output.devtoolModuleFilenameTemplate,
372							fallbackModuleFilenameTemplate:
373								options.output.devtoolFallbackModuleFilenameTemplate,
374							append: hidden ? false : undefined,
375							module: moduleMaps ? true : !cheap,
376							columns: !cheap,
377							noSources,
378							namespace: options.output.devtoolNamespace,
379							debugIds
380						}).apply(compiler);
381					} else if (use.includes("eval")) {
382						const EvalDevToolModulePlugin = require("./EvalDevToolModulePlugin");
383	
384						new EvalDevToolModulePlugin({
385							moduleFilenameTemplate:
386								options.output.devtoolModuleFilenameTemplate,
387							namespace: options.output.devtoolNamespace
388						}).apply(compiler);
389					}
390				}
391			}
392	
